class Solution {
public:
    string lastSubstring(string s) {
        int n = s.size();
        string res = "";
        for (int i = 0; i < n; i++) {
            string substr = s.substr(i);
            if (substr > res) {
                res = substr;
            }
        }
        return res;
    }
};

